            marathiMeaning = "आपल्या जबाबदाऱ्या पार पाडताना किंवा संकटांशी लढताना मन आतून देवाच्या नामस्मरणात शांत ठेवावे.",
            marathiApplication = "कठीण काळात घाबरून न जाता आपले कर्तव्य पूर्ण करा, मनामध्ये शांती टिकवून ठेवा.",
            focusTopic = "Inner Peace in Action"
