        Shloka(
            chapter = 9,
            verse = 22,
            text = "अनन्याश्चिन्तयन्तो मां ये जनाः पर्युपासते |\nतेषां नित्याभियुक्तानां योगक्षेमं वहाम्यहम् || २२ ||",
            transliteration = "ananyāś cintayanto māṁ ye janāḥ paryupāsate\nteṣāṁ nityābhiyuktānāṁ yoga-kṣemaṁ vahāmy aham",
            englishTranslation = "But those who worship Me, meditating on My transcendental form, to them who are ever united with Me, I carry what they lack and preserve what they have.",
