            marathiMeaning = "जे पूर्ण निष्ठेने आपल्या चांगुलपणावर व देवावर विश्वास ठेवतात, त्यांच्या सर्व गरजा आणि सुरक्षिततेची जबाबदारी निसर्ग घेतो.",
            marathiApplication = "भविष्याची अनावश्यक चिंता सोडा. तुमचे प्रामाणिक प्रयत्न आणि भक्ती तुम्हाला कधीही उपाशी ठेवणार नाही.",
            focusTopic = "Divine Protection & Trust"
        ),
        Shloka(
            chapter = 10,
            verse = 11,
            text = "तेषामेवानुकम्पार्थमहमज्ञानजं तमः |\nनाशयाम्यात्मभावस्थो ज्ञानदीपेन भास्वता || ११ ||",
            transliteration = "teṣām evānukampārtham aham ajñāna-jaṁ tamaḥ\nnāśayāmy ātma-bhāva-stho jñāna-dīpena bhāsvatā",
            englishTranslation = "To show them special mercy, I, dwelling in their hearts, destroy with the shining lamp of knowledge the darkness born of ignorance.",
