            englishApplication = "When confused about a major choice, meditate silently. Your pure conscience will light the right path.",
            hindiTranslation = "उन पर विशेष कृपा करने के लिए, मैं उनके हृदयों में निवास करते हुए, ज्ञान के दैदीप्यमान दीपक द्वारा अज्ञान से उत्पन्न अंधकार को नष्ट कर देता हूँ।",
            hindiMeaning = "परम ज्ञान हमारे भीतर ही है। जब हम अत्यंत दुविधा में होते हैं, तब हमारी अंतरात्मा की आवाज अंधकार को नष्ट कर मार्ग दिखाती है।",
            hindiApplication = "जब किसी बड़े फैसले में उलझें हों, तो शांत बैठकर ध्यान लगाएं। आपकी अंतरात्मा सही राह दिखाएगी।",
            marathiTranslation = "त्यांच्यावर अनुकंपा (दया) करण्यासाठी त्यांच्या अंतःकरणात राहणारा मी, त्यांच्या अज्ञानाचा अंधकार ज्ञानाच्या तेजस्वी दिव्याने नष्ट करतो.",
            marathiMeaning = "खरे ज्ञान आपल्या हृदयातच वसलेले आहे. जेव्हा मन गोंधळलेले असते, तेव्हा ध्यान केल्याने योग्य मार्ग सापडतो.",
            marathiApplication = "मोठ्या निर्णयांच्या वेळी शांत बसून आत्मचिंतन करा, उजेड नक्कीच दिसेल.",
            focusTopic = "Destroying Ignorance"
        ),
        Shloka(
            chapter = 11,
            verse = 33,
            text = "तस्मात्त्वमुत्तिष्ठ यशो लभस्व जित्वा शत्रून्भुङ्क्ष्व राज्यं समृद्धम् |\nमयैवैते निहताः पूर्वमेव निमित्तमात्रं भव सव्यसाचिन् || ३३ ||",
            transliteration = "tasmāt tvam uttiṣṭha yaśo labhasva jitvā śatrūn bhuṅkṣva rājyaṁ samṛddham\nmayaivaite nihatāḥ pūrvam eva nimitta-mātraṁ bhava savya-sācin",
            englishTranslation = "Therefore arrive, conquer your enemies, and enjoy a prosperous kingdom! They are already slain by My arrangement; be but an instrument in My play, O Savyasachin (Arjuna).",
            englishMeaning = "Everything is part of a grander cosmic design. We are mere instruments (Nimitta-matra). Overcome laziness and arrogance, rise up, and perform your glorious part.",
            englishApplication = "Accept that you cannot control everything, but you must play your role with high dedication. Be the instrument of positive change.",
            hindiTranslation = "अतः तुम उठो! यश प्राप्त करो, शत्रुओं को जीतो और समृद्ध राज्य का भोग करो। ये सब तो मेरे द्वारा पहले ही मारे जा चुके हैं, तुम तो केवल निमित्त मात्र बनो, हे सव्यसाची!",
            hindiMeaning = "सब कुछ ब्रह्मांडीय योजना के अनुसार पहले से तय है। हमें बस अहंकार और आलस्य छोड़कर अपने हिस्से का बेहतरीन काम करना है।",
            hindiApplication = "यह स्वीकार करें कि आप सब कुछ अकेले नहीं कर रहे हैं, आप केवल एक माध्यम हैं। जिम्मेदारी लें और काम शुरू करें।",
            marathiTranslation = "म्हणून तू उठ आणि यश मिळव! शत्रूंना जिंकून समृद्ध राज्याचा उपभोग घे. हे सर्व आधीच माझ्याकडून मारले गेले आहेत, हे अर्जुना, तू फक्त निमित्त मात्र हो.",
            marathiMeaning = "विश्वनियंत्याच्या योजनेनुसार सर्व काही आधीच ठरलेले आहे. आपण फक्त आपले कर्तव्य उत्तम प्रकारे बजावणारे माध्यम बनले पाहिजे.",
            marathiApplication = "आळस झटकून कामाला लागा. चांगल्या कामासाठी देवाचे एक साधन (निमित्त) बना.",
            focusTopic = "Being an Active Instrument"
        ),
        Shloka(
            chapter = 12,
            verse = 15,
            text = "यस्मान्नोद्विजते लोको लोकान्नोद्विजते च यः |\nहर्षामर्षभयोद्वेगैर्मुक्तो यः स च मे प्रियः || १५ ||",
            transliteration = "yasmān nodvijate loko lokān nodvijate ca yaḥ\nharṣāmarṣa-bhayodvegair mukto yaḥ sa ca me priyaḥ",
