            hindiApplication = "दूसरों से अपनी तुलना करना बंद करें। समझें कि सब अलग हैं लेकिन अंततः एक ही ऊर्जा का हिस्सा हैं।",
            marathiTranslation = "कारण जो प्रत्येक जीवात परमेश्वराला समान रूपाने पाहतो, तो आपल्या मनाद्वारे स्वतःचा घात (नुकसान) करत नाही; यामुळे तो उत्तम गतीला प्राप्त होतो.",
            marathiMeaning = "प्रत्येक माणसात देवाचे रूप पाहिल्याने आपल्या मनातील द्वेष संपतो आणि आपण स्वतःचे मानसिक नुकसान करत नाही.",
            marathiApplication = "कोणाविषयी कडू भावना धरू नका. स्वतःची तुलना इतरांशी करून स्वतःला त्रास देऊ नका.",
            focusTopic = "Universal Unity"
