        Shloka(
            chapter = 14,
            verse = 20,
            text = "गुणानेतानतीत्य त्रीन्देही देहसमुद्भवान् |\nजन्ममृत्युजरादुःखैर्विमुक्तोऽमृतमश्नुते || २० ||",
            transliteration = "guṇān etān atītya trīn dehī deha-samudbhavān\njanma-mṛtyu-jarā-duḥkhair vimukto ’mṛtam aśnute",
            englishTranslation = "When the embodied being is able to transcend these three modes associated with the material body, he can become free from birth, death, old age, and their distresses and enjoy immortality even in this life.",
            englishMeaning = "Transcending the three material tendencies: Tamas (laziness), Rajas (frenetic desire/aggression), and Sattva (intellectual pride), leads to ultimate mental liberation.",
            englishApplication = "Observe your moods. Shift from laziness (Tamas) or hyper-agitation (Rajas) to calm awareness and transcend them.",
            hindiTranslation = "जब देहधारी जीव शरीर की उत्पत्ति के कारणभूत इन तीनों गुणों (सत्व, रज, तम) को पार कर जाता है, तब वह जन्म, मृत्यु, वृद्धावस्था तथा इनके दुखों से मुक्त होकर परम आनंद का अनुभव करता है।",
            hindiMeaning = "आलस्य (तमोगुण), जुनून और गुस्सा (रजोगुण) और ज्ञान का अभिमान (सतोगुण) – इन तीनों प्रवृत्तियों से ऊपर उठने वाला मानसिक शांति पाता है।",
            hindiApplication = "अपने मूड पर नजर रखें। आलस्य को त्यागें, बेवजह के गुस्से से बचें और हमेशा शांत भाव में रहें।",
            marathiTranslation = "जेव्हा हा देहधारी जीव शरीराच्या उत्पत्तीला कारणीभूत असणाऱ्या तीन गुणांना (सत्व, रज, तम) ओलांडून वर जातो, तेव्हा तो जन्म, मृत्यू, वृद्धत्व आणि दुःखातून मुक्त होऊन अमृत तत्त्व मिळवतो.",
            marathiMeaning = "आळस (तम), अतिमहत्त्वाकांक्षा (रज) आणि ज्ञानाचा ताठा (सत्व) यांच्या पार गेल्याने मनाला खरी मुक्ती अनुभवता येते.",
            marathiApplication = "स्वतःच्या प्रवृत्ती ओळखा. आळस किंवा उतावळेपणा झटकून तटस्थपणे वागायला शिका.",
            focusTopic = "Mastering Your Moods"
        ),
        Shloka(
            chapter = 15,
            verse = 15,
            text = "सर्वस्य चाहं हृदि सन्निविष्टो मत्त: स्मृतिर्ज्ञानमपोहनं च |\nवेदैश्च सर्वैरहमेव वेद्यो वेदान्तकृद्वेदविदेव चाहम् || १५ ||",
            transliteration = "sarvasya cāhaṁ hṛdi sanniviṣṭo mattaḥ smṛtir jñānam apohanaṁ ca\nvedaiś ca sarvair aham eva vedyo vedānta-kṛd veda-vid eva cāham",
            englishTranslation = "I am seated in everyone's heart, and from Me come memory, knowledge, and forgetfulness. By all the Vedas, I am to be known; indeed, I am the compiler of Vedanta, and I am the knower of the Vedas.",
            englishMeaning = "The ultimate source of our wisdom, memory, and gut feelings resides deep within our consciousness. Trust your inner guide.",
            englishApplication = "When studying or brainstorming, take deep breaths and trust your preparation, knowing your inner consciousness contains all answers.",
            hindiTranslation = "मैं सभी प्राणियों के हृदय में स्थित हूँ और मुझसे ही स्मृति (याददाश्त), ज्ञान और उनका लोप (भूलना) होता है। सब वेदों द्वारा मैं ही जानने योग्य हूँ, वेदांत का रचयिता और वेदों का ज्ञाता भी मैं ही हूँ।",
            hindiMeaning = "हमारे भीतर की याददाश्त, समझ और अंतर्ज्ञान (Gut Feeling) का परम स्रोत हमारे अंदर ही स्थित है। अपने अंतर्मन पर भरोसा रखें।",
